function processData(data, tierType, applyDiscount) {
  const result = [];

  // Define tier-specific logic
  const tierRules = {
    1: {
      condition: x => x.a > 10 && x.b !== 'deleted',
      multiplier: 2.5,
      discountRate: 0.15, // 15%
      excludedStatuses: ['deleted']
    },
    2: {
      condition: x => x.a > 5 && x.a <= 10 && x.b !== 'deleted' && x.b !== 'archived',
      multiplier: 1.8,
      discountRate: 0.1,  // 10%
      excludedStatuses: ['deleted', 'archived']
    },
    3: {
      condition: x => x.a >= 15 && x.b !== 'inactive', // Example: new rule for tier 3
      multiplier: 3.0,
      discountRate: 0.2,  // 20% discount
      excludedStatuses: ['inactive', 'deleted']
    },
    // You can add more tiers here easily!
    default: {
      condition: x => x.b !== 'deleted',
      multiplier: 1.0,
      discountRate: 0, // No discount
      excludedStatuses: ['deleted']
    }
  };

  // Get the appropriate rule set
  const rule = tierRules[tierType] || tierRules.default;

  for (const item of data) {
    // Skip if condition not met
    if (!rule.condition(item)) continue;

    // Calculate c value
    let cValue = item.a * rule.multiplier;

    // Apply discount if needed
    if (applyDiscount) {
      cValue -= cValue * rule.discountRate;
    }

    // Set timestamp
    item.d = new Date().getTime();

    // Add to result
    result.push(item);
  }

  return result;
}
